mapper.select:
select determinerId,
       dChinseName,
       dName,
       memo,
       author,
       modDate,
       determinerState as determinerStateNum,
       determinerType  as determinerTypeNum,
       versions,
       releaseDate,
       facturer,
       REG_ORG         as regOrg,
       on_Date         as onDate
  from synlte.FieldDeterminer


        (upper(DChinseNAME)) like upper(concat('%',concat(#{searchName},'%')))
        or upper(DNAME) like upper(concat('%',concat(#{searchName},'%')))


        and determinerType in (

            #{item}

        )


        and determinerState in (

            #{item}

        )


        and versions in (

            #{item,jdbcType=VARCHAR}

        )


        and reg_org in (

            #{item,jdbcType=VARCHAR}

        )



    order by ${sort} ${sortOrder}
